
import { defineComponent } from 'vue';
import { after } from '@noeldemartin/utils';

import Recipe from '@/models/soukai/Recipe';

import Auth from '@/services/Auth';
import Cookbook from '@/services/Cookbook';
import Ramen from '@/services/Ramen';

import AppFooter from '@/components/AppFooter.vue';
import AppHeader from '@/components/AppHeader.vue';
import AppLoader from '@/components/AppLoader.vue';
import LoginForm from '@/components/LoginForm.vue';
import NoCookbook from '@/components/NoCookbook.vue';
import NoRamen from '@/components/NoRamen.vue';
import RamenComponent from '@/components/Ramen.vue';

type Data = {
    showLoading: boolean,
    isLoading: boolean;
    isLoggedIn: boolean;
    wasLoggedIn: boolean;
    isCookbookAvailable: boolean;
    ramen: Recipe | null;
    errorMessage: string | null;
};

export default defineComponent({
    name: 'App',
    components: {
        AppFooter,
        AppHeader,
        AppLoader,
        LoginForm,
        NoCookbook,
        NoRamen,
        Ramen: RamenComponent,
    },
    data: (): Data => ({
        showLoading: false,
        isLoading: true,
        isLoggedIn: false,
        wasLoggedIn: false,
        isCookbookAvailable: false,
        ramen: null,
        errorMessage: null,
    }),
    computed: {
        showHeader(): boolean {
            return this.isLoggedIn || (!!this.errorMessage && this.wasLoggedIn);
        },
    },
    async created() {
        try {
            await Promise.all([
                Auth.start(),
                Cookbook.start(),
                Ramen.start(),
            ]);

            Cookbook.loaded.then(() => this.isCookbookAvailable = true);
            Ramen.loaded.then(() => this.ramen = Ramen.model);
        } catch (error) {
            console.error(error);

            this.errorMessage = error.message;
        } finally {
            this.isLoggedIn = Auth.isLoggedIn;
            this.wasLoggedIn = Auth.wasLoggedIn;
            this.isLoading = false;
            this.showLoading = false;
        }
    },
    async mounted() {
        await after({ milliseconds: 500 });

        this.showLoading = this.isLoading;
    },
});
